### **C++ Program: Binary Search Tree Dictionary**

This program implements a dictionary using a **Binary Search Tree (BST)** in C++. The dictionary allows users to:
- Insert words and their definitions.
- Look up a word and print its definition.
- Delete a word and its definition.
- Print all words and definitions in the dictionary.

---

## **Step-by-Step Explanation**

### **1. Define the Node Structure**
Each node in the BST will store:
- A `word` (string).
- A `definition` (string).
- Pointers to the left and right children.

### **2. Implement BST Operations**
We will implement the following operations:
- **Insert**: Add a word and its definition to the BST.
- **Search**: Find a word and return its definition.
- **Delete**: Remove a word and its definition from the BST.
- **Print All Words**: Traverse the BST and print all words and definitions.

### **3. User Interface**
The program will prompt the user for input and display appropriate messages to guide them.

---

## **C++ Code**

```cpp
#include <iostream>
#include <string>
using namespace std;

// Node structure for BST
struct Node {
    string word;
    string definition;
    Node* left;
    Node* right;

    Node(string w, string d) : word(w), definition(d), left(nullptr), right(nullptr) {}
};

// BST class
class DictionaryBST {
private:
    Node* root;

    // Helper functions
    Node* insert(Node* node, string word, string definition);
    Node* search(Node* node, string word);
    Node* deleteNode(Node* node, string word);
    void printInOrder(Node* node);
    void destroyTree(Node* node);

public:
    DictionaryBST() : root(nullptr) {}

    void insertWord(string word, string definition);
    bool searchWord(string word);
    void deleteWord(string word);
    void printAllWords();
};

// Helper function to insert a node
Node* DictionaryBST::insert(Node* node, string word, string definition) {
    if (node == nullptr) {
        return new Node(word, definition);
    }

    if (word < node->word) {
        node->left = insert(node->left, word, definition);
    } else if (word > node->word) {
        node->right = insert(node->right, word, definition);
    } else {
        // Word already exists; update the definition
        node->definition = definition;
    }

    return node;
}

// Helper function to search for a word
Node* DictionaryBST::search(Node* node, string word) {
    if (node == nullptr || node->word == word) {
        return node;
    }

    if (word < node->word) {
        return search(node->left, word);
    } else {
        return search(node->right, word);
    }
}

// Helper function to delete a node
Node* DictionaryBST::deleteNode(Node* node, string word) {
    if (node == nullptr) return node;

    if (word < node->word) {
        node->left = deleteNode(node->left, word);
    } else if (word > node->word) {
        node->right = deleteNode(node->right, word);
    } else {
        // Node with only one child or no child
        if (node->left == nullptr) {
            Node* temp = node->right;
            delete node;
            return temp;
        } else if (node->right == nullptr) {
            Node* temp = node->left;
            delete node;
            return temp;
        }

        // Node with two children: Get the inorder successor (smallest in the right subtree)
        Node* temp = node->right;
        while (temp->left != nullptr) {
            temp = temp->left;
        }

        // Copy the inorder successor's data to this node
        node->word = temp->word;
        node->definition = temp->definition;

        // Delete the inorder successor
        node->right = deleteNode(node->right, temp->word);
    }

    return node;
}

// Helper function to print the tree in-order
void DictionaryBST::printInOrder(Node* node) {
    if (node != nullptr) {
        printInOrder(node->left);
        cout << "Word: " << node->word << " | Definition: " << node->definition << endl;
        printInOrder(node->right);
    }
}

// Helper function to destroy the tree
void DictionaryBST::destroyTree(Node* node) {
    if (node != nullptr) {
        destroyTree(node->left);
        destroyTree(node->right);
        delete node;
    }
}

// Public functions
void DictionaryBST::insertWord(string word, string definition) {
    root = insert(root, word, definition);
    cout << "Word \"" << word << "\" added with definition: \"" << definition << "\"." << endl;
}

bool DictionaryBST::searchWord(string word) {
    Node* result = search(root, word);
    if (result != nullptr) {
        cout << "Definition of \"" << word << "\": " << result->definition << endl;
        return true;
    } else {
        cout << "Word \"" << word << "\" not found in the dictionary." << endl;
        return false;
    }
}

void DictionaryBST::deleteWord(string word) {
    root = deleteNode(root, word);
    cout << "Word \"" << word << "\" deleted from the dictionary." << endl;
}

void DictionaryBST::printAllWords() {
    if (root == nullptr) {
        cout << "The dictionary is empty." << endl;
        return;
    }
    cout << "Dictionary Contents:" << endl;
    printInOrder(root);
}

// Main function
int main() {
    DictionaryBST dict;
    int choice;
    string word, definition;

    while (true) {
        cout << "\n--- Dictionary Menu ---" << endl;
        cout << "1. Insert Word and Definition" << endl;
        cout << "2. Search for a Word" << endl;
        cout << "3. Delete a Word" << endl;
        cout << "4. Print All Words" << endl;
        cout << "5. Exit" << endl;
        cout << "Enter your choice: ";
        cin >> choice;

        switch (choice) {
            case 1:
                cout << "Enter the word: ";
                cin >> word;
                cout << "Enter the definition: ";
                cin.ignore(); // To ignore the newline character
                getline(cin, definition);
                dict.insertWord(word, definition);
                break;
            case 2:
                cout << "Enter the word to search: ";
                cin >> word;
                dict.searchWord(word);
                break;
            case 3:
                cout << "Enter the word to delete: ";
                cin >> word;
                dict.deleteWord(word);
                break;
            case 4:
                dict.printAllWords();
                break;
            case 5:
                cout << "Exiting the dictionary. Goodbye!" << endl;
                dict.destroyTree(root);
                return 0;
            default:
                cout << "Invalid choice. Please try again." << endl;
        }
    }

    return 0;
}
```

