#### **3.3. Data Persistence (Using JSON)**
```csharp
public static class DataPersistence
{
    public static void SaveScores(Dictionary<int, int> scores, string filePath)
    {
        string json = JsonConvert.SerializeObject(scores, Formatting.Indented);
        File.WriteAllText(filePath, json);
    }

    public static Dictionary<int, int> LoadScores(string filePath)
    {
        if (File.Exists(filePath))
        {
            string json = File.ReadAllText(filePath);
            return JsonConvert.DeserializeObject<Dictionary<int, int>>(json);
        }
        return new Dictionary<int, int>();
    }
}
